var e=[{id:`L2_1`,type:`dialog`,speaker:`LEEJISOO_SIX_NULL_NULL`,text:{KOREA:` 시작됐어요. 대장.`,JPN:` 始まりましたね。隊長。`,ENG:`It's begun, Commander.`,TWN:`已經開始了，隊長。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`LEEJISOO_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`NAYUBIN_SIX_NULL_NULL`,text:{KOREA:` ……그래요. 여기까지 오는 데 오래 걸렸네요.`,JPN:` ……そうですね。ここまで長かったですね。`,ENG:`...Yes. It took us a long time to get here.`,TWN:`……嗯，來的路上花了不少時間呢。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`NAYUBIN_SIX_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:` 확실히 보통 실력이 아니시네요.`,JPN:` 確かにとんでもない強さですね。`,ENG:`I can see that you're not an easy opponent.`,TWN:`實力確實非同凡響。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:` 납도를 하셨으니 그쪽 간격에 들어가기 전에 예의상 여쭤 볼까요.`,JPN:` 剣を収められたので、そちらの間合いに入る前に一応聞いておきます。`,ENG:`Since you've put your sword away, let me ask out of courtesy.`,TWN:`不過既然已經不準備打了，我想冒昧地問一下。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:` 무슨 말씀을 하시는 거죠? 시작이라니요?`,JPN:` どういう意味ですか？　始まるって？`,ENG:`What are you talking about? What began?`,TWN:`你們在說什麼呢？請問是開始什麼？`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEEJISOO_SIX_NULL_NULL`,text:{KOREA:` 직접 보도록 해, 아가.`,JPN:` 自分で確認しな、坊や。`,ENG:`Come and see for yourself, boy.`,TWN:`你親眼看看吧，孩子。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`LEEJISOO_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`LEEJISOO_SIX_NULL_NULL`,text:{KOREA:` 구도자의 후예인 너라면 저게 뭔지 바로 알 수 있겠지.`,JPN:` 求道者の後継者であるお前なら、あれが何なのかすぐにわかるだろう。`,ENG:`As the descendant of the Seeker of Truth, you would know what that is.`,TWN:`身為求道者後裔的你，應該馬上就能知道那是什麼吧。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`LEEJISOO_SIX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:` 구도자……?`,JPN:` 求道者……？`,ENG:`Seeker of Truth...?`,TWN:`求道者……？`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:null,text:{KOREA:` <color=#ffd34c>울브즈베인 – 레거시 모드 기동</color>`,JPN:` <color=#ffd34c>ウルブズベイン – レガシーモード起動</color>`,ENG:`<color=#ffd34c>Wolvesbane - Legacy Mode activated.</color>`,TWN:`<color=#ffd34c>狼之災禍 – 遺留模式啟動</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:null,text:{KOREA:` <color=#ffd34c>전술 업데이트 - 발퀴레 근접 반응형 집속검</color>`,JPN:` <color=#ffd34c>戦術アップデート – ワルキューレ近接反応型集束剣</color>`,ENG:`<color=#ffd34c>Tactical update - Valkyrie melee response focus blade.</color>`,TWN:`<color=#ffd34c>戰術升級 – 女武神近戰反應型聚能劍</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:` 큭……?! 발키리의 검술을 인간이 어떻게……!`,JPN:` くっ……！？　ヴァルキリーの剣術を人間がどうやって……！`,ENG:`Kggk...?! How could a normal human being use the swordsmanship of the Valkyrie...?!`,TWN:`唔……？！人類怎麼會使用女武神的劍法……！`},stage:{bg:`MS_1113`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:null,text:{KOREA:` <color=#ffd34c>전술 업데이트 – 바라밀 명도</color>`,JPN:` <color=#ffd34c>戦術アップデート – 波羅蜜命刀</color>`,ENG:`<color=#ffd34c>Tactical Update – The Sword of Paramita</color>`,TWN:`<color=#ffd34c>戰術升級 – 波羅蜜命刀</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:` 저건…… 제 검술을 미나 양이 어떻게?`,JPN:` あれは……僕の剣術をどうやってミナさんが？`,ENG:`That's... How is Mina using my swordsmanship...?`,TWN:`那是……米娜怎麼會用我的劍法？`},stage:{bg:`MS_1113_1`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:` 큭?! 만신창이로 이런 움직임을 보이다니…….`,JPN:` くっ！？　満身創痍の状態でこんな動きを見せるなんて……`,ENG:`Kggh?! How did you pull that move in that state...?`,TWN:`唔？！她傷得那麼重，是怎麼做到的……`},stage:{bg:`MS_1113`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:` 늑대의 힘을 이끌어낸다고 달라질 것 같습니까?!`,JPN:` 狼の力を引き出したところで、変わるとでも！？`,ENG:`Do you think drawing out the power of the Wolf will change anything?!`,TWN:`你以為激發出狼的力量就能改變什麼嗎？！`},stage:{bg:`MS_1113`,slots:{L:null,C:null,R:null}}}];export{e as default};